import check from ".../icons/check.png";

const Datos = () => {
  const cabinData = {
    name: "Cabaña Sauce",
    description:
      "Amplia, cómoda y luminosa. La Cabaña Sauce es ideal para compartir en familia o con amigos, con espacios pensados para descansar y disfrutar cada momento.",
    price: "$25.000",
    features: [
      "Capacidad para 7 personas",
      "2 Dormitorios",
      "Aire Acondicionado",
      "Smart TV",
      "3 baños",
    ],
  };

  return (
    <div className="flex-1 flex flex-col justify-center px-[3.5vh]">
      {/* TÍTULO + DESCRIPCIÓN */}
      <div>
        <h1 className="titulo-playfair text-[#7D6239] text-[40px] font-bold text-center">
          {cabinData.name}
        </h1>

        <div
          className="h-[6px] w-[20vh] mx-auto rounded-[4px] mb-[4vh]"
          style={{
            background: "linear-gradient(90deg, #F27507 0%, #CC2329 100%)",
          }}
        />

        <p className="text-[#626262] font-light text-[17px]">
          {cabinData.description}
        </p>
      </div>

      {/* FEATURES */}
      <div className="my-[2vh] flex flex-col gap-[1.5vh]">
        {cabinData.features.map((item, index) => (
          <div key={index} className="flex gap-[1vh] items-center">
            <img src={check} alt="check" className="w-[3vh]" />
            <h3 className="text-[#6E6E6E] text-[15px]">{item}</h3>
          </div>
        ))}
      </div>

      {/* PRECIO + CTA */}
      <div className="flex w-[95%] gap-[7vh] mx-auto my-[2vh]">
        <div className="flex flex-1 flex-col items-center">
          <h2 className="text-[#F27507] font-extrabold text-[35px]/[0.9]">
            {cabinData.price}
          </h2>
          <h4 className="text-[#B3B3B3] text-[15px] text-center">C/Noche</h4>
        </div>

        <div className="flex flex-1 items-center justify-center">
          <button
            className="text-white text-[20px] font-semibold rounded-[12px] px-[3.5vh] py-[1vh] italic"
            style={{
              background: "linear-gradient(90deg, #F27507 0%, #CC2329 100%)",
            }}
          >
            RESERVAR
          </button>
        </div>
      </div>
    </div>
  );
};

export default Datos;
